), norm AS (
  -- Пара наименований встречается в источнике несколько раз с одинаковым составом — min()
  -- делает результат детерминированным независимо от порядка строк.
  SELECT regexp_replace(translate(lower(btrim(name)), 'ё', 'е'), '\s+', ' ', 'g') AS key,
         min(btrim(composition)) AS composition
    FROM src
   GROUP BY 1
)
UPDATE rates r
   SET description = n.composition
  FROM norm n
 WHERE regexp_replace(translate(lower(btrim(r.name)), 'ё', 'е'), '\s+', ' ', 'g') = n.key
   AND r.description IS DISTINCT FROM n.composition;
